#!/usr/bin/env node
/**
 * Debug script untuk troubleshoot quality parsing issue
 * Jalankan di server backend
 */

import axios from "axios";
import { fetchStreamQualities } from "./src/services/streamQualities.js";
import { parseIptvStreamUrl } from "./src/utils/iptvStreamUrl.js";

// Test dengan channel GTV
const testChannelId = 9;
const testUserAgentHeader = "NusaVision/1.0";
const testReferer = null;
const testUserId = 1; // Demo user

let accessToken = null;

// Demo API call dari backend sendiri
async function testWithAxios() {
  console.log("\n DEBUG: Testing fetchStreamQualities function directly\n");

  // Simulasi calling API getChannel first
  const streamUrl = "https://d2tjypxxy769fn.cloudfront.net/out/v1/b8b9b1d5f80f45649b4a3619291551ab/in"; // GTV manifest

  console.log(` Input manifest URL: ${streamUrl.substring(0, 80)}...`);
  console.log(` User ID: ${testUserId}`);
  console.log(` User Agent: ${testUserAgentHeader}`);
  console.log(` Referer: ${testReferer || "null"}`);

  try {
    console.log("\n Calling fetchStreamQualities()...\n");
    const result = await fetchStreamQualities(
      streamUrl,
      testUserAgentHeader,
      testReferer,
      testUserId
    );

    console.log("✅ Response received:");
    console.log(`   Total data items: ${result.data.length}`);
    console.log(`   Master URL: ${result.masterUrl.substring(0, 60)}...`);

    console.log("\n Quality options:");
    result.data.forEach((q, i) => {
      const heightStr = q.height ? `${q.height}p` : "N/A";
      const bwStr = q.bandwidth
        ? `${(q.bandwidth / 1000000).toFixed(2)} Mbps`
        : "N/A";
      const auto = q.id === "auto" ? " [AUTO]" : "";
      console.log(
        `   [${i}] ${q.label.padEnd(10)} h=${heightStr.padEnd(6)} bw=${bwStr}${auto}`
      );
    });

    if (result.data.length === 5) {
      console.log("\n✅ SUCCESS: 5 quality options found (1 AUTO + 4 resolutions)");
    } else if (result.data.length === 1) {
      console.log("\n❌ FAIL: Only 1 quality option found - parsing still broken!");
    } else {
      console.log(`\n⚠️  Unexpected: ${result.data.length} quality options found`);
    }

    return result.data.length > 1;
  } catch (err) {
    console.error("❌ Error calling fetchStreamQualities():");
    console.error(`   ${err.message}`);
    if (err.stack) {
      console.error("\nStack trace:");
      console.error(err.stack);
    }
    return false;
  }
}

async function verifyFile() {
  console.log("\n────────────────────────────────────────────────────────────\n");
  console.log(" DEBUG: Verify streamQualities.js file content\n");

  try {
    const fs = await import("fs");
    const path = await import("path");

    const filePath = path.resolve("./src/services/streamQualities.js");
    const content = fs.readFileSync(filePath, "utf-8");

    // Check key functions are present
    const hasEnhancedParsing = content.includes("// Fallback to AdaptationSet-level dimensions");
    const hasLabelWithBandwidth = content.includes("function labelFromHeight(height, bandwidth)");
    const hasDebugLogging = content.includes('console.info("[streamQualities] Ditemukan"');

    console.log(` File path: ${filePath}`);
    console.log(`   File size: ${content.length} bytes`);
    console.log(`   Lines: ${content.split("\n").length}`);

    console.log("\n✔️ Verification checks:");
    console.log(
      `   ${hasEnhancedParsing ? "✅" : "❌"} Enhanced DASH parsing (setHeight/setWidth fallback)`
    );
    console.log(
      `   ${hasLabelWithBandwidth ? "✅" : "❌"} Label generation with bandwidth support`
    );
    console.log(`   ${hasDebugLogging ? "✅" : "❌"} Debug logging added`);

    if (hasEnhancedParsing && hasLabelWithBandwidth && hasDebugLogging) {
      console.log("\n✅ File appears to be correctly updated!");
      return true;
    } else {
      console.log("\n❌ File may NOT be correctly updated - missing key changes");
      return false;
    }
  } catch (err) {
    console.error(`❌ Error reading file: ${err.message}`);
    return false;
  }
}

async function checkDeduplication() {
  console.log("\n────────────────────────────────────────────────────────────\n");
  console.log(" DEBUG: Check deduplication logic\n");

  try {
    const content = await import("./src/services/streamQualities.js");
    const source = await import("fs");

    const filePath = "./src/services/streamQualities.js";
    const fileContent = source.readFileSync(filePath, "utf-8");

    const hasNewDedup =
      fileContent.includes("const byHeight = new Map()") &&
      fileContent.includes("const byBandwidth = new Map()");

    console.log(`Deduplication logic:`);
    console.log(
      `   ${hasNewDedup ? "✅" : "❌"} Uses new Map-based deduplication (byHeight + byBandwidth)`
    );

    if (!hasNewDedup) {
      console.log("\n⚠️ WARNING: Old deduplication logic still in place!");
      console.log("   This could cause resolutions not to be extracted.");
    }

    return hasNewDedup;
  } catch (err) {
    console.error(`Error: ${err.message}`);
    return false;
  }
}

async function main() {
  console.log("╔════════════════════════════════════════════════════════╗");
  console.log("║   DEBUG: Quality Parsing Issue Investigation            ║");
  console.log("║   Server: tv.mqlspot.my.id                             ║");
  console.log("╚════════════════════════════════════════════════════════╝");

  // Step 1: Verify file
  const fileOk = await verifyFile();

  // Step 2: Check deduplication
  const dedupOk = await checkDeduplication();

  // Step 3: Test function directly
  const testOk = await testWithAxios();

  // Summary
  console.log("\n" + "═".repeat(60));
  console.log("\n DEBUG SUMMARY:");
  console.log(`   File correctly updated: ${fileOk ? "✅" : "❌"}`);
  console.log(`   Deduplication logic: ${dedupOk ? "✅" : "❌"}`);
  console.log(`   Function test result: ${testOk ? "✅" : "❌"}`);

  if (fileOk && dedupOk && testOk) {
    console.log("\n✅ All checks PASSED - Function works correctly!");
    console.log("   Issue might be in API caching or something else.");
  } else {
    console.log("\n❌ Some checks FAILED - File may not be properly updated.");
    console.log("   Possible solutions:");
    console.log("   1. Verify file was correctly copied to server");
    console.log("   2. Check file permissions");
    console.log("   3. Restart backend service again");
  }
}

main().catch((err) => {
  console.error("❌ Fatal error:", err);
  process.exit(1);
});

#!/usr/bin/env node
/**
 * Comprehensive diagnostic for server quality parsing
 * Run this on the backend server: node diagnostic-full.js
 */

import axios from "axios";

const API_BASE = "https://tv.mqlspot.my.id";
const TEST_CHANNEL_ID = 9; // GTV

console.log(`
╔════════════════════════════════════════════════════════════╗
║  COMPREHENSIVE DIAGNOSTIC - Quality Parsing Issue          ║
║  Date: June 9, 2026                                        ║
╚════════════════════════════════════════════════════════════╝
`);

// Test 1: Check if we can reach API
console.log(" TEST 1: API Connectivity");
console.log("━".repeat(60));

try {
  const health = await axios.get(`${API_BASE}/health`, { timeout: 5000 });
  console.log("✅ API is responding");
  console.log(`   Status: ${health.status}`);
  console.log(`   Database: ${health.data.database || "N/A"}`);
} catch (err) {
  console.log(`❌ API not responding: ${err.message}`);
  process.exit(1);
}

// Test 2: Login and get token
console.log("\n TEST 2: Authentication");
console.log("━".repeat(60));

let token;
try {
  const login = await axios.post(`${API_BASE}/api/auth/login`, {
    email: "sihiver@yahoo.com",
    password: "459922",
  });
  token =
    login.data.token ||
    login.data.accessToken ||
    login.data.data?.token;
  console.log("✅ Login successful");
  console.log(`   Token: ${token?.substring(0, 20)}...`);
} catch (err) {
  console.log(`❌ Login failed: ${err.message}`);
  process.exit(1);
}

// Test 3: Get channel stream URL
console.log("\n TEST 3: Get Channel Stream URL");
console.log("━".repeat(60));

let streamUrl;
try {
  const stream = await axios.get(`${API_BASE}/api/channels/${TEST_CHANNEL_ID}/stream`, {
    headers: { Authorization: `Bearer ${token}` },
  });
  streamUrl = stream.data.streamUrl;
  console.log("✅ Got stream URL");
  console.log(`   URL: ${streamUrl?.substring(0, 80)}...`);
} catch (err) {
  console.log(`❌ Failed to get stream URL: ${err.message}`);
  process.exit(1);
}

// Test 4: Download and check manifest
console.log("\n TEST 4: Manifest Content");
console.log("━".repeat(60));

let manifestContent;
try {
  const manifest = await axios.get(streamUrl, { timeout: 10000, responseType: "text" });
  manifestContent = manifest.data;
  const contentType = manifest.headers["content-type"];

  console.log("✅ Manifest downloaded");
  console.log(`   Size: ${manifestContent.length} bytes`);
  console.log(`   Content-Type: ${contentType}`);
  console.log(`   Format: ${manifestContent.includes("<MPD") ? "DASH" : manifestContent.includes("#EXTM3U") ? "HLS" : "Unknown"}`);

  // Count representations
  const repMatches = manifestContent.match(/<Representation/g);
  console.log(`   Representations: ${repMatches?.length || 0}`);
} catch (err) {
  console.log(`❌ Failed to get manifest: ${err.message}`);
  process.exit(1);
}

// Test 5: Call quality endpoint
console.log("\n TEST 5: Quality Endpoint Response");
console.log("━".repeat(60));

try {
  const qualities = await axios.get(
    `${API_BASE}/api/channels/${TEST_CHANNEL_ID}/stream/qualities`,
    { headers: { Authorization: `Bearer ${token}` } }
  );

  const data = qualities.data.data || [];
  console.log("✅ Endpoint called");
  console.log(`   Response code: ${qualities.status}`);
  console.log(`   Total options: ${data.length}`);

  if (data.length > 0) {
    console.log("\n   Quality Options:");
    data.forEach((q, i) => {
      const h = q.height ? `${q.height}p` : "N/A";
      const b = q.bandwidth ? `${(q.bandwidth / 1000000).toFixed(2)}Mbps` : "N/A";
      console.log(`     [${i}] ${q.label.padEnd(10)} (h=${h}, bw=${b})`);
    });
  } else {
    console.log("   ⚠️ No quality options returned");
  }
} catch (err) {
  console.log(`❌ Endpoint call failed: ${err.message}`);
  if (err.response?.data) {
    console.log(`   Response: ${JSON.stringify(err.response.data)}`);
  }
  process.exit(1);
}

// Test 6: Analysis
console.log("\n TEST 6: Analysis & Diagnosis");
console.log("━".repeat(60));

const hasManifest = manifestContent && manifestContent.length > 0;
const isDAsh = manifestContent?.includes("<MPD");
const hasRepresentations =
  manifestContent?.match(/<Representation/g)?.length > 0 || false;

const qualitiesResp = await axios.get(
  `${API_BASE}/api/channels/${TEST_CHANNEL_ID}/stream/qualities`,
  { headers: { Authorization: `Bearer ${token}` } }
);
const qualityCount = (qualitiesResp.data.data || []).length;

console.log("Summary:");
console.log(`  ✅ Manifest downloaded: ${hasManifest ? "Yes" : "No"}`);
console.log(`  ${isDAsh ? "✅" : "❌"} Is DASH format: ${isDAsh ? "Yes" : "No"}`);
console.log(
  `  ${hasRepresentations ? "✅" : "❌"} Has representations: ${hasRepresentations ? "Yes" : "No"}`
);
console.log(`  ${qualityCount > 1 ? "✅" : "❌"} API returns multiple options: ${qualityCount > 1 ? "Yes" : "No"}`);

console.log("\nDiagnosis:");
if (!hasManifest) {
  console.log("  ❌ Cannot download manifest");
} else if (!isDAsh) {
  console.log("  ⚠️ Manifest is not DASH format");
} else if (!hasRepresentations) {
  console.log("  ❌ DASH manifest has no Representations");
} else if (qualityCount <= 1) {
  console.log("  ⚠️ Manifest has representations but API only returns 1 quality");
  console.log("     Possible issues:");
  console.log("     1. File not updated correctly");
  console.log("     2. Service not restarted with new file");
  console.log("     3. Parsing logic has a bug");
} else {
  console.log("  ✅ Everything working correctly!");
}

// Test 7: Provide next steps
console.log("\n RECOMMENDED NEXT STEPS");
console.log("━".repeat(60));

if (qualityCount <= 1) {
  console.log(`
1. SSH to server and verify file update:
   ssh user@tv.mqlspot.my.id
   grep -n "setHeight" /path/to/backend/src/services/streamQualities.js
   # Should output line number if file is updated

2. Check if using enhanced parsing:
   grep "const byHeight = new Map()" /path/to/backend/src/services/streamQualities.js
   # Should find the line

3. Restart backend service:
   pkill -9 node
   cd /path/to/backend
   npm run dev
   # Wait 5-10 seconds

4. Clear Redis cache:
   redis-cli FLUSHALL

5. Test again:
   curl -s https://tv.mqlspot.my.id/api/channels/9/stream/qualities \\
     -H "Authorization: Bearer $TOKEN" | jq '.data | length'
   # Should be 5 now, not 1
  `);
} else {
  console.log("✅ Quality parsing is working correctly!");
  console.log("No action needed.");
}

console.log("\n" + "═".repeat(60) + "\n");

import axios from "axios";
import { parseStringPromise } from "xml2js";
import { parseIptvStreamUrl } from "../utils/iptvStreamUrl.js";
import { generateStreamToken } from "./streamToken.js";

function requestHeaders(userAgent, referer) {
  const headers = {};
  if (userAgent) headers["User-Agent"] = userAgent;
  if (referer) headers.Referer = referer;
  return headers;
}

function labelFromHeight(height) {
  if (!height) return "Kualitas";
  if (height >= 1080) return "1080p";
  if (height >= 720) return "720p";
  if (height >= 480) return "480p";
  if (height >= 360) return "360p";
  return `${height}p`;
}

/** Satu entri per resolusi; jika ada beberapa variant, ambil bandwidth tertinggi. */
function dedupeQualitiesByHeight(qualities) {
  const byKey = new Map();

  for (const q of qualities) {
    const key =
      q.height != null ? `h${q.height}` : `bw${q.bandwidth ?? byKey.size}`;
    const existing = byKey.get(key);
    if (!existing || (q.bandwidth || 0) > (existing.bandwidth || 0)) {
      byKey.set(key, q);
    }
  }

  return [...byKey.values()].sort((a, b) => (b.height || 0) - (a.height || 0));
}

function resolveUrl(uri, baseUrl) {
  try {
    return new URL(uri.trim(), baseUrl).href;
  } catch {
    return null;
  }
}

function parseHlsQualities(text, masterUrl) {
  const lines = text.split("\n").map((l) => l.trim());
  const qualities = [];
  const seen = new Set();

  for (let i = 0; i < lines.length; i++) {
    if (!lines[i].startsWith("#EXT-X-STREAM-INF")) continue;
    const line = lines[i];
    const resMatch = line.match(/RESOLUTION=(\d+)x(\d+)/i);
    const height = resMatch ? parseInt(resMatch[2], 10) : null;
    const bwMatch = line.match(/BANDWIDTH=(\d+)/i);
    const bandwidth = bwMatch ? parseInt(bwMatch[1], 10) : null;

    let uri = "";
    for (let j = i + 1; j < lines.length; j++) {
      if (!lines[j] || lines[j].startsWith("#")) continue;
      uri = lines[j];
      break;
    }
    if (!uri) continue;

    const abs = resolveUrl(uri, masterUrl);
    if (!abs || seen.has(abs)) continue;
    seen.add(abs);

    const id = height ? `h${height}` : `bw${bandwidth || qualities.length}`;
    qualities.push({
      id,
      label: labelFromHeight(height),
      height,
      bandwidth,
      url: abs,
    });
  }

  return qualities.sort((a, b) => (b.height || 0) - (a.height || 0));
}

async function parseDashQualities(xml, manifestUrl) {
  const parsed = await parseStringPromise(xml, {
    explicitArray: false,
    mergeAttrs: true,
  });

  const mpd = parsed.MPD;
  if (!mpd) return [];

  const periods = []
    .concat(mpd.Period || [])
    .filter(Boolean);
  const qualities = [];
  const seen = new Set();

  for (const period of periods) {
    const sets = []
      .concat(period.AdaptationSet || [])
      .filter(Boolean);

    for (const set of sets) {
      const mime = (set.mimeType || set.contentType || "").toLowerCase();
      if (mime && !mime.includes("video")) continue;

      const reps = []
        .concat(set.Representation || [])
        .filter(Boolean);

      for (const rep of reps) {
        const height = rep.height ? parseInt(rep.height, 10) : null;
        const bandwidth = rep.bandwidth ? parseInt(rep.bandwidth, 10) : null;

        let path = "";
        if (rep.SegmentTemplate?.media) {
          const st = rep.SegmentTemplate;
          const media = st.media;
          const init = st.initialization || "";
          path = init.replace("$RepresentationID$", rep.id || "") || media;
        }
        if (rep.BaseURL) {
          path = typeof rep.BaseURL === "string" ? rep.BaseURL : rep.BaseURL;
        }

        const base =
          (typeof set.BaseURL === "string" ? set.BaseURL : null) ||
          manifestUrl;

        const abs = path.startsWith("http")
          ? path
          : resolveUrl(path || "", manifestUrl);

        const key = `${height || 0}-${bandwidth || 0}`;
        if (seen.has(key)) continue;
        seen.add(key);

        qualities.push({
          id: height ? `h${height}` : `bw${bandwidth || qualities.length}`,
          label: labelFromHeight(height),
          height,
          bandwidth,
          url: abs || manifestUrl,
        });
      }
    }
  }

  return qualities.sort((a, b) => (b.height || 0) - (a.height || 0));
}

/**
 * Ambil daftar resolusi dari manifest HLS/DASH di CDN.
 */
export async function fetchStreamQualities(manifestUrl, userAgent, referer, userId) {
  const { url: cleanUrl } = parseIptvStreamUrl(manifestUrl);
  const headers = requestHeaders(userAgent, referer);

  let variants = [];

  try {
    const { data, headers: resHeaders } = await axios.get(cleanUrl, {
      headers,
      timeout: 15_000,
      responseType: "text",
      validateStatus: (s) => s >= 200 && s < 400,
    });

    const contentType = String(resHeaders["content-type"] || "");
    const body = typeof data === "string" ? data : String(data);

    if (
      cleanUrl.includes(".m3u8") ||
      contentType.includes("mpegurl") ||
      body.includes("#EXTM3U")
    ) {
      if (body.includes("#EXT-X-STREAM-INF")) {
        variants = parseHlsQualities(body, cleanUrl);
      }
    } else if (cleanUrl.includes(".mpd") || contentType.includes("dash+xml")) {
      variants = await parseDashQualities(body, cleanUrl);
    }
  } catch (err) {
    console.warn("[streamQualities]", cleanUrl, err.message);
  }

  variants = dedupeQualitiesByHeight(variants);

  const withToken = variants.map((v) => {
    const { streamUrl } = generateStreamToken(v.url, userId);
    return { ...v, url: streamUrl };
  });

  const data = [
    { id: "auto", label: "Otomatis", height: null, bandwidth: null, url: null },
    ...withToken,
  ];

  return { data, masterUrl: generateStreamToken(cleanUrl, userId).streamUrl };
}

import axios from "axios";
import { parseStringPromise } from "xml2js";
import { parseIptvStreamUrl } from "../utils/iptvStreamUrl.js";
import { generateStreamToken } from "./streamToken.js";

function requestHeaders(userAgent, referer) {
  const headers = {};
  // Set User-Agent - use provided one or fallback to browser-like default
  headers["User-Agent"] = userAgent || "Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36";
  if (referer) headers.Referer = referer;
  return headers;
}

 function labelFromHeight(height, bandwidth) {
  if (height) {
    if (height >= 1080) return "1080p";
    if (height >= 720) return "720p";
    if (height >= 480) return "480p";
    if (height >= 360) return "360p";
    return `${height}p`;
  }

  // Fallback to bandwidth-based label if height not available
  if (bandwidth) {
    if (bandwidth >= 5000000) return "HD";
    if (bandwidth >= 2000000) return "SD";
    return "Kualitas";
  }

  return "Kualitas";
}

/** Satu entri per resolusi; jika ada beberapa variant, ambil bandwidth tertinggi. */
function dedupeQualitiesByHeight(qualities) {
  if (!qualities.length) return [];

  const byHeight = new Map();
  const byBandwidth = new Map();

  for (const q of qualities) {
    if (q.height != null) {
      // Group by height, keep highest bandwidth
      const key = `h${q.height}`;
      const existing = byHeight.get(key);
      if (!existing || (q.bandwidth || 0) > (existing.bandwidth || 0)) {
        byHeight.set(key, q);
      }
    } else if (q.bandwidth != null) {
      // If no height, use bandwidth as key
      const key = `bw${q.bandwidth}`;
      byBandwidth.set(key, q);
    }
  }

  // Combine: height-based first, then bandwidth-based
  const result = [...byHeight.values(), ...byBandwidth.values()];
  return result.sort((a, b) => (b.height || 0) - (a.height || 0) || (b.bandwidth || 0) - (a.bandwidth || 0));
}

function resolveUrl(uri, baseUrl) {
  try {
    return new URL(uri.trim(), baseUrl).href;
  } catch {
    return null;
  }
}

function parseHlsQualities(text, masterUrl) {
  const lines = text.split("\n").map((l) => l.trim());
  const qualities = [];
  const seen = new Set();

  for (let i = 0; i < lines.length; i++) {
    if (!lines[i].startsWith("#EXT-X-STREAM-INF")) continue;
    const line = lines[i];
    const resMatch = line.match(/RESOLUTION=(\d+)x(\d+)/i);
    const height = resMatch ? parseInt(resMatch[2], 10) : null;
    const bwMatch = line.match(/BANDWIDTH=(\d+)/i);
    const bandwidth = bwMatch ? parseInt(bwMatch[1], 10) : null;

    let uri = "";
    for (let j = i + 1; j < lines.length; j++) {
      if (!lines[j] || lines[j].startsWith("#")) continue;
      uri = lines[j];
      break;
    }
    if (!uri) continue;

    const abs = resolveUrl(uri, masterUrl);
    if (!abs || seen.has(abs)) continue;
    seen.add(abs);

    const id = height ? `h${height}` : `bw${bandwidth || qualities.length}`;
    qualities.push({
      id,
      label: labelFromHeight(height, bandwidth),
      height,
      bandwidth,
      url: abs,
    });
  }

  return qualities.sort((a, b) => (b.height || 0) - (a.height || 0));
}

async function parseDashQualities(xml, manifestUrl) {
  const parsed = await parseStringPromise(xml, {
    explicitArray: false,
    mergeAttrs: true,
  });

  const mpd = parsed.MPD;
  if (!mpd) return [];

  const periods = []
    .concat(mpd.Period || [])
    .filter(Boolean);
  const qualities = [];
  const seen = new Set();

  for (const period of periods) {
    const sets = []
      .concat(period.AdaptationSet || [])
      .filter(Boolean);

    for (const set of sets) {
      const mime = (set.mimeType || set.contentType || "").toLowerCase();
      if (mime && !mime.includes("video")) continue;

      // Get dimensions from AdaptationSet if not specified per Representation
      const setWidth = set.width ? parseInt(set.width, 10) : null;
      const setHeight = set.height ? parseInt(set.height, 10) : null;

      const reps = []
        .concat(set.Representation || [])
        .filter(Boolean);

      for (const rep of reps) {
        // Extract height, with fallbacks
        let height = rep.height ? parseInt(rep.height, 10) : null;
        let width = rep.width ? parseInt(rep.width, 10) : null;

        // Fallback to AdaptationSet-level dimensions if not in Representation
        if (!height) height = setHeight;
        if (!width) width = setWidth;

        // Fallback: calculate height from width if only width is available
        if (!height && width) {
          // Assume 16:9 aspect ratio as default
          height = Math.round(width * 9 / 16);
        }

        const bandwidth = rep.bandwidth ? parseInt(rep.bandwidth, 10) : null;

        let path = "";
        if (rep.SegmentTemplate?.media) {
          const st = rep.SegmentTemplate;
          const media = st.media;
          const init = st.initialization || "";
          path = init.replace("$RepresentationID$", rep.id || "") || media;
        }
        if (rep.BaseURL) {
          path = typeof rep.BaseURL === "string" ? rep.BaseURL : rep.BaseURL;
        }

        const base =
          (typeof set.BaseURL === "string" ? set.BaseURL : null) ||
          manifestUrl;

        const abs = path.startsWith("http")
          ? path
          : resolveUrl(path || "", manifestUrl);

        const key = `${height || 0}-${bandwidth || 0}`;
        if (seen.has(key)) continue;
        seen.add(key);

        qualities.push({
          id: height ? `h${height}` : `bw${bandwidth || qualities.length}`,
          label: labelFromHeight(height, bandwidth),
          height,
          bandwidth,
          url: abs || manifestUrl,
        });
      }
    }
  }

  return qualities.sort((a, b) => (b.height || 0) - (a.height || 0));
}

/**
 * Ambil daftar resolusi dari manifest HLS/DASH di CDN.
 */
export async function fetchStreamQualities(manifestUrl, userAgent, referer, userId) {
  const { url: cleanUrl } = parseIptvStreamUrl(manifestUrl);
  const headers = requestHeaders(userAgent, referer);

  let variants = [];

  try {
    // Try to fetch with enhanced headers for CDN access
    const axiosConfig = {
      headers: {
        ...headers,
        'Accept': '*/*',
        'Accept-Encoding': 'gzip, deflate, br',
        'Cache-Control': 'no-cache',
        'Pragma': 'no-cache',
        'Accept-Language': 'en-US,en;q=0.9',
      },
      timeout: 15_000,
      responseType: "text",
      validateStatus: (s) => s >= 200 && s < 400,
      maxRedirects: 5,
    };

    const { data, headers: resHeaders } = await axios.get(cleanUrl, axiosConfig);

    const contentType = String(resHeaders["content-type"] || "");
    const body = typeof data === "string" ? data : String(data);

    if (
      cleanUrl.includes(".m3u8") ||
      contentType.includes("mpegurl") ||
      body.includes("#EXTM3U")
    ) {
      if (body.includes("#EXT-X-STREAM-INF")) {
        variants = parseHlsQualities(body, cleanUrl);
      }
    } else if (cleanUrl.includes(".mpd") || contentType.includes("dash+xml")) {
      variants = await parseDashQualities(body, cleanUrl);
    }
  } catch (err) {
    // Handle CDN blocking (403 Forbidden) - common with geo-restricted CDNs
    if (err.response?.status === 403) {
      console.warn("[streamQualities] 403 Forbidden - CDN may be geo-blocking this IP");
      console.warn("[streamQualities] Manifest URL:", cleanUrl.substring(0, 100));
      console.warn("[streamQualities] Client will handle manifest parsing");
      // Don't throw - let client player handle it
      variants = [];
    } else if (err.response?.status) {
      console.warn("[streamQualities]", cleanUrl, `HTTP ${err.response.status}: ${err.message}`);
    } else {
      console.warn("[streamQualities]", cleanUrl, err.message);
    }
  }

  variants = dedupeQualitiesByHeight(variants);

  // Debug: log variants found
  if (variants.length === 0) {
    console.info("[streamQualities] No variants parsed from manifest (normal if CDN blocked)");
  } else {
    console.info("[streamQualities] Ditemukan", variants.length, "variant(s) untuk", cleanUrl);
    variants.forEach(v => {
      console.info(`  - ${v.label} (height: ${v.height}, bandwidth: ${v.bandwidth})`);
    });
  }

  const withToken = variants.map((v) => {
    const { streamUrl } = generateStreamToken(v.url, userId);
    return { ...v, url: streamUrl };
  });

  const data = [
    { id: "auto", label: "Otomatis", height: null, bandwidth: null, url: null },
    ...withToken,
  ];

  return { data, masterUrl: generateStreamToken(cleanUrl, userId).streamUrl };
}

@import url("https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@400;600;700;800;900&family=Barlow:wght@400;500;600;700&display=swap");

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  width: 100%;
  height: 100%;
}

body {
  margin: 0;
  width: 100%;
  height: 100%;
  background: #08080f;
  font-family: "Barlow Condensed", "Barlow", "Segoe UI", sans-serif;
  color: #e2e8f0;
  -webkit-font-smoothing: antialiased;
  overflow: hidden;
}

#root {
  display: flex;
  flex-direction: column;
  width: 100%;
  min-width: 100%;
  max-width: none;
  height: 100%;
  min-height: 100vh;
  min-height: 100dvh;
}

button,
input,
select {
  font-family: inherit;
}

/* Satu shell fullscreen — tanpa max-width */
.admin-app {
  display: flex;
  flex-direction: column;
  flex: 1;
  width: 100%;
  min-width: 0;
  min-height: 0;
  height: 100%;
  background: #08080f;
  overflow: hidden;
}

.admin-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-shrink: 0;
  width: 100%;
  padding: 0 28px;
  height: 54px;
  background: rgba(5, 5, 12, 0.98);
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
}

.admin-main {
  flex: 1;
  display: flex;
  flex-direction: column;
  width: 100%;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
}

/* Semua halaman mengisi area konten */
.admin-page {
  flex: 1;
  width: 100%;
  min-width: 0;
  padding: 28px 32px;
  overflow-y: auto;
  overflow-x: hidden;
}

.admin-grid-4 {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 16px;
}

.admin-grid-3 {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 16px;
}

.admin-grid-2 {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 20px;
}

.nav-tab {
  background: none;
  border: none;
  color: #888;
  border-radius: 8px;
  padding: 7px 14px;
  font-size: 12;
  font-weight: 400;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 6px;
  letter-spacing: 0.5px;
}

.nav-tab--active {
  background: rgba(255, 107, 53, 0.12);
  color: #ff6b35;
  font-weight: 700;
}

.avatar {
  width: 32px;
  height: 32px;
  border-radius: 16px;
  background: linear-gradient(135deg, #ff6b35, #f7c59f);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
  font-weight: 700;
  color: #fff;
}

.notif-badge {
  position: absolute;
  top: -2px;
  right: -2px;
  width: 14px;
  height: 14px;
  border-radius: 7px;
  background: #fc8181;
  font-size: 9px;
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
}

select option {
  background: #1a1a2e;
  color: #fff;
}

/* ─── Login ─── */
.login-page {
  min-height: 100vh;
  min-height: 100dvh;
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  background: radial-gradient(ellipse at 30% 20%, rgba(255, 107, 53, 0.12), transparent 50%),
    radial-gradient(ellipse at 80% 80%, rgba(99, 179, 237, 0.08), transparent 40%), #030308;
  padding: 24px;
}

.login-card {
  width: 100%;
  max-width: 420px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 20px;
  padding: 40px 36px;
  box-shadow: 0 40px 100px rgba(0, 0, 0, 0.6);
}

.login-brand {
  text-align: center;
  margin-bottom: 8px;
}

.login-brand-nusa {
  font-size: 22px;
  font-weight: 900;
  letter-spacing: 3px;
}

.login-brand-vision {
  font-size: 22px;
  font-weight: 900;
  letter-spacing: 3px;
  color: #ff6b35;
}

.login-brand-sub {
  font-size: 10px;
  color: #555;
  letter-spacing: 4px;
  margin-top: 6px;
  font-family: monospace;
}

.login-desc {
  text-align: center;
  font-size: 13px;
  color: #888;
  margin: 0 0 28px;
  line-height: 1.5;
}

.login-form {
  display: flex;
  flex-direction: column;
  gap: 18px;
}

.login-label {
  display: flex;
  flex-direction: column;
  gap: 8px;
  font-size: 10px;
  color: #888;
  letter-spacing: 1px;
  font-weight: 700;
}

.login-input {
  width: 100%;
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.12);
  border-radius: 10px;
  color: #fff;
  font-size: 14px;
  padding: 12px 14px;
  outline: none;
  box-sizing: border-box;
}

.login-input:focus {
  border-color: rgba(255, 107, 53, 0.5);
}

.login-pass-wrap {
  position: relative;
}

.login-pass-wrap .login-input {
  padding-right: 44px;
}

.login-pass-toggle {
  position: absolute;
  right: 10px;
  top: 50%;
  transform: translateY(-50%);
  background: none;
  border: none;
  cursor: pointer;
  font-size: 16px;
  opacity: 0.7;
}

.login-submit {
  margin-top: 8px;
  width: 100%;
  background: #ff6b35;
  border: none;
  border-radius: 10px;
  color: #fff;
  font-size: 14px;
  font-weight: 800;
  padding: 14px;
  cursor: pointer;
  letter-spacing: 0.5px;
}

.login-submit:disabled {
  opacity: 0.65;
  cursor: wait;
}

.login-submit:hover:not(:disabled) {
  filter: brightness(1.08);
}

.login-error {
  padding: 10px 14px;
  background: rgba(252, 129, 129, 0.12);
  border: 1px solid rgba(252, 129, 129, 0.3);
  border-radius: 10px;
  font-size: 12px;
  color: #fc8181;
}

.login-hint {
  margin-top: 24px;
  font-size: 11px;
  color: #555;
  text-align: center;
  line-height: 1.6;
}

.login-hint code {
  color: #ff6b35;
  font-size: 10px;
}

@media (max-width: 1200px) {
  .admin-grid-4,
  .admin-grid-3 {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 768px) {
  .admin-grid-4,
  .admin-grid-3,
  .admin-grid-2 {
    grid-template-columns: 1fr;
  }
}

